scripts.script:
import java.nio.file.Path
import java.nio.file.Paths
String resolveTreePath(String raw, Path baseDir) {
    if (raw == null || raw.trim().isEmpty()) return null
    Path p = Paths.get(raw.trim())
    if (!p.isAbsolute()) {
        p = baseDir.resolve(raw.trim()).normalize()
    } else {
        p = p.normalize()
    }
    return p.toString()
}

Path baseDir = Paths.get(project.basedir as String)
String userCli = session.userProperties.getProperty('mhr.wsdl.resources.root')
if (userCli != null && !userCli.trim().isEmpty()) {
    project.properties.setProperty('mhr.wsdl.resources.root', resolveTreePath(userCli, baseDir))
    return
}
String envTree = System.getenv('MHR_WSDL_RESOURCES_ROOT')
if (envTree != null && !envTree.trim().isEmpty()) {
    project.properties.setProperty('mhr.wsdl.resources.root', resolveTreePath(envTree, baseDir))
    return
}
String fromSettings = null
def settings = session.getSettings()
if (settings != null) {
    def activeIds = settings.getActiveProfiles()
    if (activeIds != null && !activeIds.isEmpty()) {
        try {
            def pmap = settings.getProfilesAsMap()
            if (pmap != null) {
                for (def pid : activeIds) {
                    if (fromSettings != null) break
                    def prof = pmap.get(pid)
                    if (prof?.getProperties() != null) {
                        String v = prof.getProperties().getProperty('mhr.wsdl.resources.root')
                        if (v != null && !v.trim().isEmpty()) {
                            fromSettings = v.trim()
                        }
                    }
                }
            }
        } catch (Exception ignored) {
            settings.getProfiles()?.each { prof ->
                if (fromSettings == null && activeIds.contains(prof.getId())) {
                    String v = prof.getProperties()?.getProperty('mhr.wsdl.resources.root')
                    if (v != null && !v.trim().isEmpty()) fromSettings = v.trim()
                }
            }
        }
    }
}
if (fromSettings != null) {
    project.properties.setProperty('mhr.wsdl.resources.root', resolveTreePath(fromSettings, baseDir))
    return
}
project.properties.setProperty('mhr.wsdl.resources.root',
        baseDir.resolve('wsdls').resolve('src').resolve('main').resolve('resources').toAbsolutePath().normalize().toString())

def clean = project.properties.getProperty('mhr.wsdl.codegen.clean', 'false')
if (!'true'.equalsIgnoreCase(clean.trim())) {
    return
}
def bd = project.build.directory as File
def partsBase = new File(bd, 'generated-sources/wsimport-parts')
if (partsBase.isDirectory()) {
    partsBase.eachDir { File sub -> sub.deleteDir() }
    partsBase.deleteDir()
}
def destBase = new File(bd, 'jaxws/dest')
if (destBase.isDirectory()) {
    destBase.eachDir { File sub -> sub.deleteDir() }
}
def merged = new File(bd, 'generated-sources/wsimport')
if (merged.isDirectory()) {
    merged.deleteDir()
}
def jaxwsDir = new File(bd, 'jaxws')
if (jaxwsDir.isDirectory()) {
    jaxwsDir.deleteDir()
}

def bd = project.build.directory as File
def out = new File(bd, 'generated-sources/wsimport')
out.mkdirs()
def base = new File(bd, 'generated-sources/wsimport-parts')
def names = [
    'wsimport-b2b-document-registry',
    'wsimport-b2b-document-repository',
    'wsimport-b2b-get-audit-view',
    'wsimport-b2b-get-change-history-view',
    'wsimport-b2b-get-individual-details-view',
    'wsimport-b2b-get-representative-list',
    'wsimport-b2b-get-template',
    'wsimport-b2b-get-view',
    'wsimport-b2b-pcehr-profile',
    'wsimport-b2b-register-pcehr',
    'wsimport-b2b-remove-document',
    'wsimport-b2b-search-template'
]
names.each { String part ->
    def dir = new File(base, part)
    if (!dir.isDirectory()) return
    dir.eachFileRecurse(groovy.io.FileType.FILES) { File f ->
        def rel = dir.toPath().relativize(f.toPath()).toString().replace('\\', '/')
        def target = new File(out, rel)
        target.parentFile.mkdirs()
        if (!target.exists()) {
            f.withInputStream { ins -> target.withOutputStream { os -> os << ins } }
        }
    }
}
project.getCompileSourceRoots().findAll { String p -> p.contains('wsimport-parts') }.each { project.removeCompileSourceRoot(it) }
if (base.isDirectory()) {
    base.deleteDir()
}
